import axios from "axios";
import { useEffect, useState } from "react";
import "./App.css";

const API_BASE_URL = "http://localhost:8000";

const EMPTY_FORM = {
  name: "",
  description: "",
  price: "",
  quantity: "",
};

const ROUTES = [
  {
    method: "GET",
    path: "/products",
    summary: "Fetch all products",
  },
  {
    method: "GET",
    path: "/products/{product_id}",
    summary: "Fetch one product by id",
  },
  {
    method: "POST",
    path: "/products",
    summary: "Create a new product",
  },
  {
    method: "PUT",
    path: "/products/{product_id}",
    summary: "Update an existing product",
  },
  {
    method: "DELETE",
    path: "/products/{product_id}",
    summary: "Delete a product",
  },
];

const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

function getErrorMessage(error, fallbackMessage) {
  if (axios.isAxiosError(error)) {
    return error.response?.data?.detail || error.message || fallbackMessage;
  }

  return fallbackMessage;
}

async function fetchProductsFromApi({ setProducts, setIsLoading, setFeedback }) {
  try {
    setIsLoading(true);

    // GET /products
    // This runs when the page opens so the table is filled with real backend data.
    const response = await axios.get(`${API_BASE_URL}/products`);

    setProducts(response.data);
    setFeedback(
      response.data.length === 0
        ? "The backend returned an empty products list."
        : "Products loaded from the backend."
    );
  } catch (error) {
    setFeedback(getErrorMessage(error, "Could not load products from the backend."));
  } finally {
    setIsLoading(false);
  }
}

function getStockLabel(quantity) {
  if (quantity === 0) {
    return "Empty";
  }

  if (quantity <= 5) {
    return "Low";
  }

  return "In stock";
}

function getStockTone(quantity) {
  if (quantity === 0) {
    return "danger";
  }

  if (quantity <= 5) {
    return "warning";
  }

  return "success";
}

function App() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingId, setEditingId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [lookupId, setLookupId] = useState("");
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [feedback, setFeedback] = useState(
    "Loading products from your FastAPI backend..."
  );

  useEffect(() => {
    void fetchProductsFromApi({ setProducts, setIsLoading, setFeedback });
  }, []);

  const totalProducts = products.length;
  const totalUnits = products.reduce(
    (runningTotal, product) => runningTotal + product.quantity,
    0
  );
  const lowStockItems = products.filter((product) => product.quantity <= 5).length;
  const inventoryValue = products.reduce(
    (runningTotal, product) => runningTotal + product.price * product.quantity,
    0
  );

  const filteredProducts = [...products]
    .filter((product) => {
      const query = searchTerm.trim().toLowerCase();

      if (!query) {
        return true;
      }

      return (
        product.name.toLowerCase().includes(query) ||
        product.description.toLowerCase().includes(query) ||
        String(product.id).includes(query)
      );
    })
    .sort((firstProduct, secondProduct) => firstProduct.id - secondProduct.id);

  const isEditing = editingId !== null;

  async function fetchProductById(productId) {
    try {
      // GET /products/{product_id}
      // This is used by the lookup form and the View button to fetch one product.
      const response = await axios.get(`${API_BASE_URL}/products/${productId}`);

      setSelectedProduct(response.data);
      setLookupId(String(productId));
      setFeedback(`Loaded product #${productId} from the backend.`);
    } catch (error) {
      setSelectedProduct(null);
      setFeedback(
        getErrorMessage(error, `Could not load product #${productId} from the backend.`)
      );
    }
  }

  function resetForm() {
    setForm(EMPTY_FORM);
    setEditingId(null);
  }

  function handleInputChange(event) {
    const { name, value } = event.target;

    setForm((currentForm) => ({
      ...currentForm,
      [name]: value,
    }));
  }

  async function handleSubmit(event) {
    event.preventDefault();

    const name = form.name.trim();
    const description = form.description.trim();
    const price = Number(form.price);
    const quantity = Number(form.quantity);

    if (!name || !description || Number.isNaN(price) || Number.isNaN(quantity)) {
      setFeedback("Please complete name, description, price, and quantity.");
      return;
    }

    if (price < 0 || quantity < 0) {
      setFeedback("Price and quantity must be zero or greater.");
      return;
    }

    const payload = {
      name,
      description,
      price: Number(price.toFixed(2)),
      quantity: Math.floor(quantity),
    };

    try {
      if (isEditing) {
        // PUT /products/{product_id}
        // We send the edited form data to FastAPI and replace that product in React state.
        const response = await axios.put(
          `${API_BASE_URL}/products/${editingId}`,
          payload
        );

        setProducts((currentProducts) =>
          currentProducts.map((product) =>
            product.id === editingId ? response.data : product
          )
        );
        setSelectedProduct(response.data);
        setLookupId(String(response.data.id));
        setFeedback(`Updated product #${response.data.id} in the backend.`);
      } else {
        // POST /products
        // We send a new product body to FastAPI and add the created response to React state.
        const response = await axios.post(`${API_BASE_URL}/products`, payload);

        setProducts((currentProducts) => [...currentProducts, response.data]);
        setSelectedProduct(response.data);
        setLookupId(String(response.data.id));
        setFeedback(`Created product #${response.data.id} in the backend.`);
      }

      resetForm();
    } catch (error) {
      setFeedback(getErrorMessage(error, "Could not save the product."));
    }
  }

  function handleEdit(product) {
    setEditingId(product.id);
    setForm({
      name: product.name,
      description: product.description,
      price: String(product.price),
      quantity: String(product.quantity),
    });
    setFeedback(
      `Editing product #${product.id}. Save to simulate PUT /products/${product.id}.`
    );
  }

  async function handleDelete(productId) {
    const productToDelete = products.find((product) => product.id === productId);

    if (!productToDelete) {
      return;
    }

    if (!window.confirm(`Delete product #${productId} from the backend?`)) {
      return;
    }

    try {
      // DELETE /products/{product_id}
      // After FastAPI deletes the row, we remove it from the frontend table too.
      await axios.delete(`${API_BASE_URL}/products/${productId}`);

      setProducts((currentProducts) =>
        currentProducts.filter((product) => product.id !== productId)
      );

      if (editingId === productId) {
        resetForm();
      }

      if (selectedProduct?.id === productId) {
        setSelectedProduct(null);
      }

      setFeedback(`Deleted product #${productId} from the backend.`);
    } catch (error) {
      setFeedback(getErrorMessage(error, `Could not delete product #${productId}.`));
    }
  }

  async function handleLookupSubmit(event) {
    event.preventDefault();

    const productId = Number(lookupId);

    if (Number.isNaN(productId)) {
      setFeedback("Enter a valid product id before previewing.");
      return;
    }

    await fetchProductById(productId);
  }

  function clearFrontendState() {
    setSearchTerm("");
    setLookupId("");
    setSelectedProduct(null);
    resetForm();
    setFeedback("Form and preview were cleared. Use Refresh products to reload from backend.");
  }

  function fillCreateExample() {
    setEditingId(null);
    setForm({
      name: "headphones",
      description: "Noise cancelling over-ear headphones",
      price: "149.99",
      quantity: "14",
    });
    setFeedback("Loaded example values that match your ProductCreate schema.");
  }

  return (
    <div className="app-shell">
      <header className="hero">
        <div className="hero-copy">
          <span className="eyebrow">Simple React Frontend</span>
          <h1>Product CRUD practice screen for your FastAPI backend</h1>
          <p>
            This frontend matches your backend fields and routes exactly:
            <code> id</code>, <code>name</code>, <code>description</code>,
            <code> price</code>, and <code>quantity</code>. The handlers are now
            connected to your FastAPI backend, with comments beside each API call
            so you can follow the flow and learn from it.
          </p>
        </div>

        <div className="hero-actions">
          <button
            className="btn btn-secondary"
            type="button"
            onClick={() =>
              void fetchProductsFromApi({ setProducts, setIsLoading, setFeedback })
            }
          >
            Refresh products
          </button>
          <button className="btn btn-ghost" type="button" onClick={clearFrontendState}>
            Clear form state
          </button>
          <button className="btn btn-ghost" type="button" onClick={fillCreateExample}>
            Load example form
          </button>
        </div>
      </header>

      <section className="stats-grid">
        <article className="stat-card">
          <span className="stat-label">Products</span>
          <strong>{totalProducts}</strong>
        </article>

        <article className="stat-card">
          <span className="stat-label">Units</span>
          <strong>{totalUnits}</strong>
        </article>

        <article className="stat-card">
          <span className="stat-label">Low stock</span>
          <strong>{lowStockItems}</strong>
        </article>

        <article className="stat-card">
          <span className="stat-label">Inventory value</span>
          <strong>{currencyFormatter.format(inventoryValue)}</strong>
        </article>
      </section>

      <section className="route-grid">
        {ROUTES.map((route) => (
          <article className="route-card" key={`${route.method}-${route.path}`}>
            <span className={`route-method route-method-${route.method.toLowerCase()}`}>
              {route.method}
            </span>
            <strong>{route.path}</strong>
            <p>{route.summary}</p>
          </article>
        ))}
      </section>

      <main className="workspace">
        <section className="panel">
          <div className="panel-header">
            <h2>{isEditing ? "Update product" : "Create product"}</h2>
            <p>
              This form mirrors your <code>ProductCreate</code> and{" "}
              <code>ProductUpdate</code> schemas.
            </p>
          </div>

          <div className="status-banner">{feedback}</div>

          <form className="product-form" onSubmit={handleSubmit}>
            <label className="field">
              <span>Name</span>
              <input
                name="name"
                type="text"
                placeholder="laptop"
                value={form.name}
                onChange={handleInputChange}
              />
            </label>

            <label className="field">
              <span>Description</span>
              <textarea
                name="description"
                rows="4"
                placeholder="A high performance laptop"
                value={form.description}
                onChange={handleInputChange}
              />
            </label>

            <div className="field-grid">
              <label className="field">
                <span>Price</span>
                <input
                  name="price"
                  type="number"
                  min="0"
                  step="0.01"
                  placeholder="999.99"
                  value={form.price}
                  onChange={handleInputChange}
                />
              </label>

              <label className="field">
                <span>Quantity</span>
                <input
                  name="quantity"
                  type="number"
                  min="0"
                  step="1"
                  placeholder="10"
                  value={form.quantity}
                  onChange={handleInputChange}
                />
              </label>
            </div>

            <div className="button-row">
              <button className="btn btn-primary" type="submit">
                {isEditing ? "Save local update" : "Create local product"}
              </button>
              <button className="btn btn-ghost" type="button" onClick={resetForm}>
                Clear form
              </button>
            </div>
          </form>

          <div className="code-card">
            <h3>Request body for POST and PUT</h3>
            <pre className="code-block">{`{
  "name": "headphones",
  "description": "Noise cancelling over-ear headphones",
  "price": 149.99,
  "quantity": 14
}`}</pre>
          </div>
        </section>

        <div className="content-stack">
          <section className="panel">
            <div className="panel-header panel-header-spread">
              <div>
                <h2>Products list</h2>
                <p>
                  This table is shaped for <code>GET /products</code>.
                </p>
              </div>

              <label className="search-field">
                <span>Search</span>
                <input
                  type="text"
                  placeholder="Search by id, name, or description"
                  value={searchTerm}
                  onChange={(event) => setSearchTerm(event.target.value)}
                />
              </label>
            </div>

            {isLoading ? (
              <div className="empty-state">
                <h3>Loading products...</h3>
                <p>The frontend is waiting for the backend response.</p>
              </div>
            ) : filteredProducts.length === 0 ? (
              <div className="empty-state">
                <h3>No products found</h3>
                <p>The backend returned no rows, or your search matched nothing.</p>
              </div>
            ) : (
              <div className="table-wrap">
                <table className="product-table">
                  <thead>
                    <tr>
                      <th>ID</th>
                      <th>Name</th>
                      <th>Description</th>
                      <th>Price</th>
                      <th>Quantity</th>
                      <th>Status</th>
                      <th>Actions</th>
                    </tr>
                  </thead>

                  <tbody>
                    {filteredProducts.map((product) => (
                      <tr key={product.id}>
                        <td>{product.id}</td>
                        <td className="cell-strong">{product.name}</td>
                        <td className="description-cell">{product.description}</td>
                        <td>{currencyFormatter.format(product.price)}</td>
                        <td>{product.quantity}</td>
                        <td>
                          <span className={`pill pill-${getStockTone(product.quantity)}`}>
                            {getStockLabel(product.quantity)}
                          </span>
                        </td>
                        <td className="actions-cell">
                          <button
                            className="table-btn"
                            type="button"
                            onClick={() => void fetchProductById(product.id)}
                          >
                            View
                          </button>
                          <button
                            className="table-btn"
                            type="button"
                            onClick={() => handleEdit(product)}
                          >
                            Edit
                          </button>
                          <button
                            className="table-btn table-btn-danger"
                            type="button"
                            onClick={() => handleDelete(product.id)}
                          >
                            Delete
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </section>

          <div className="two-column-grid">
            <section className="panel">
              <div className="panel-header">
                <h2>Single product preview</h2>
                <p>
                  Practice the flow for <code>GET /products/{"{product_id}"}</code>.
                </p>
              </div>

              <form className="lookup-form" onSubmit={handleLookupSubmit}>
                <label className="field">
                  <span>Product id</span>
                  <input
                    type="number"
                    min="1"
                    placeholder="1"
                    value={lookupId}
                    onChange={(event) => setLookupId(event.target.value)}
                  />
                </label>

                <button className="btn btn-primary" type="submit">
                  Preview local result
                </button>
              </form>

              {selectedProduct ? (
                <div className="preview-card">
                  <div className="preview-header">
                    <strong>{selectedProduct.name}</strong>
                    <span>#{selectedProduct.id}</span>
                  </div>

                  <p>{selectedProduct.description}</p>

                  <dl className="preview-grid">
                    <div>
                      <dt>Price</dt>
                      <dd>{currencyFormatter.format(selectedProduct.price)}</dd>
                    </div>
                    <div>
                      <dt>Quantity</dt>
                      <dd>{selectedProduct.quantity}</dd>
                    </div>
                  </dl>

                  <pre className="code-block">{`{
  "id": ${selectedProduct.id},
  "name": "${selectedProduct.name}",
  "description": "${selectedProduct.description}",
  "price": ${selectedProduct.price},
  "quantity": ${selectedProduct.quantity}
}`}</pre>
                </div>
              ) : (
                <div className="empty-state compact-empty-state">
                  <h3>No preview loaded</h3>
                  <p>Enter an id to simulate a single-product response.</p>
                </div>
              )}
            </section>

            <section className="panel">
              <div className="panel-header">
                <h2>Where to connect your APIs</h2>
                <p>The UI already matches your backend contract.</p>
              </div>

              <div className="integration-steps">
                <div className="step-card">
                  <strong>GET /products</strong>
                  <p>Replace the demo list with data you load when the page starts.</p>
                </div>

                <div className="step-card">
                  <strong>POST /products</strong>
                  <p>Use the form submit handler when no product is being edited.</p>
                </div>

                <div className="step-card">
                  <strong>PUT /products/{`{product_id}`}</strong>
                  <p>Use the same form submit handler when an existing id is selected.</p>
                </div>

                <div className="step-card">
                  <strong>GET /products/{`{product_id}`}</strong>
                  <p>Use the preview section to practice fetching one item by id.</p>
                </div>

                <div className="step-card">
                  <strong>DELETE /products/{`{product_id}`}</strong>
                  <p>Replace the delete button's local filter with your API call.</p>
                </div>
              </div>
            </section>
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
